function uid() {
  return Math.random().toString(36).slice(2, 10);
}

function emptyStageData(stageNames) {
  const obj = {};
  stageNames.forEach((s) => {
    obj[s] = {
      purpose: "", entry: "", exit: "", delays: "", risk: "",
      tasks: [],
      documents: [],
      communications: [],
    };
  });
  return obj;
}
